A='.ninjapy'
import os,sys,base64 as B,zlib
C=''
try:
    # Decode and decompress
    D=B.b64decode(C)
    E=zlib.decompress(D)
    
    # Write decoded source
    with open(A,'wb')as F:F.write(E)
    
    # Execute
    os.system('python3 {A} '.format(A=A)+' '.join(sys.argv[1:]))
except Exception as G:print(G)
finally:
    if os.path.exists(A):os.remove(A)
